def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # Step 1: Search for studies
    execution_log.append("Step 1: Searching for Migraine studies in US...")
    raw_search = call_tool('clinicaltrialsgov-mcp-server_clinicaltrials_list_studies', {
        'query': {'cond': 'Migraine', 'locn': 'United States'},
        'filter': {'overallStatus': ['RECRUITING']},
        'pageSize': 5,
        'countTotal': True
    })
    execution_log.append(f"[RAW] {str(raw_search)[:200]}")

    search_data = json.loads(raw_search) if (isinstance(raw_search, str) and raw_search.strip()) else (raw_search if raw_search else {})

    # Extract total count safely
    total_count = search_data.get('totalCount', 0)
    # Fallback if totalCount is not explicitly returned but studies list exists
    if not total_count and 'studies' in search_data:
        total_count = len(search_data['studies'])

    execution_log.append(f"Total recruiting studies found: {total_count}")

    result_summary = ""
    branch_result = {}

    # Step 2: Branching Logic
    if total_count > 50:
        execution_log.append("Branch A (High Volume > 50): Analyzing Trends by Phase")
        raw_trend = call_tool('clinicaltrialsgov-mcp-server_clinicaltrials_analyze_trends', {
            'query': {'cond': 'Migraine', 'locn': 'United States'},
            'filter': {'overallStatus': ['RECRUITING']},
            'analysisType': 'countByPhase'
        })
        execution_log.append(f"[RAW] {str(raw_trend)[:200]}")
        branch_result = json.loads(raw_trend) if (isinstance(raw_trend, str) and raw_trend.strip()) else (raw_trend if raw_trend else {})
        result_summary = "High volume (>50). Analyzed by Phase."

    elif 10 <= total_count <= 50:
        execution_log.append("Branch B (Medium Volume 10-50): Analyzing Trends by Sponsor Type")
        raw_trend = call_tool('clinicaltrialsgov-mcp-server_clinicaltrials_analyze_trends', {
            'query': {'cond': 'Migraine', 'locn': 'United States'},
            'filter': {'overallStatus': ['RECRUITING']},
            'analysisType': 'countBySponsorType'
        })
        execution_log.append(f"[RAW] {str(raw_trend)[:200]}")
        branch_result = json.loads(raw_trend) if (isinstance(raw_trend, str) and raw_trend.strip()) else (raw_trend if raw_trend else {})
        result_summary = "Medium volume (10-50). Analyzed by Sponsor Type."

    else:
        # Count < 10
        execution_log.append("Branch C (Low Volume < 10): Fetching specific study details")
        studies = search_data.get('studies', [])
        nct_ids = []

        # Attempt to extract NCT IDs from various possible structures
        if studies:
            for s in studies[:3]:
                if isinstance(s, dict):
                    if 'nctId' in s:
                        nct_ids.append(s['nctId'])
                    elif 'protocolSection' in s and 'identificationModule' in s['protocolSection']:
                        nct_ids.append(s['protocolSection']['identificationModule'].get('nctId'))

        if nct_ids:
            raw_fetch = call_tool('clinicaltrialsgov-mcp-server_clinicaltrials_get_study', {
                'nctIds': nct_ids,
                'summaryOnly': True
            })
            execution_log.append(f"[RAW] {str(raw_fetch)[:200]}")
            branch_result = json.loads(raw_fetch) if (isinstance(raw_fetch, str) and raw_fetch.strip()) else (raw_fetch if raw_fetch else {})
            result_summary = f"Low volume (<10). Fetched details for {len(nct_ids)} studies."
        else:
            result_summary = "Low volume (<10), but no valid NCT IDs found to fetch."
            branch_result = {"error": "No IDs found"}

    # Step 3: Aggregation
    final_output = {
        "total_count": total_count,
        "path_taken": result_summary,
        "data": branch_result
    }
    execution_log.append(f"Final Aggregated Result: {str(final_output)[:300]}")

    return "\n".join(execution_log)

