def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []
    final_summary = []

    # Step 1: Arxiv Search
    execution_log.append("Step 1: Searching arXiv")
    search_args = {
        "query": "Chain of Thought",
        "date_from": "2024-05-13",
        "date_to": "2024-05-20"
    }
    raw_search = call_tool("arxiv_search_papers", search_args)
    execution_log.append(f"[RAW] {str(raw_search)[:200]}")

    # Parse arXiv results (handling potential string or list return)
    arxiv_results = []
    if isinstance(raw_search, str):
        try:
            parsed = json.loads(raw_search)
            # Some tools return a list directly, others wrap in a dict
            if isinstance(parsed, list): arxiv_results = parsed
            elif isinstance(parsed, dict): arxiv_results = parsed.get("results", []) or parsed.get("papers", [])
        except:
            pass
    elif isinstance(raw_search, list):
        arxiv_results = raw_search
    elif isinstance(raw_search, dict):
        arxiv_results = raw_search.get("results", [])

    paper_count = len(arxiv_results)
    execution_log.append(f"Arxiv paper count: {paper_count}")

    # Step 2: Branching Logic
    if paper_count >= 3:
        execution_log.append("Branch A: High volume arXiv results")
        first_paper = arxiv_results[0]
        paper_id = first_paper.get("id") or first_paper.get("entry_id")
        original_title = first_paper.get("title", "Unknown Title")

        # Download
        call_tool("arxiv_download_paper", {"paper_id": paper_id})

        # Read
        raw_content = call_tool("arxiv_read_paper", {"paper_id": paper_id})
        content_str = str(raw_content).lower()

        final_title = original_title
        if "benchmark" in content_str:
            execution_log.append("Sub-branch A1: 'benchmark' found, translating title")
            trans_args = {
                "text": [{"text": original_title, "translatable": True}],
                "target": "es-ES"
            }
            raw_trans = call_tool("lara-translate_translate", trans_args)
            try:
                trans_data = json.loads(raw_trans) if isinstance(raw_trans, str) else raw_trans
                # Assuming structure matches input or standard return
                if isinstance(trans_data, dict) and "translation" in trans_data:
                     final_title = trans_data["translation"]
                elif isinstance(trans_data, list) and len(trans_data) > 0:
                     final_title = trans_data[0].get("translation", original_title)
            except:
                pass
        else:
            execution_log.append("Sub-branch A2: 'benchmark' not found, using original title")

        # Notion Post
        notion_args = {
            "parent": {"database_id": "db-123"},
            "properties": {
                "Name": {
                    "title": [{"text": {"content": final_title}}]
                }
            }
        }
        call_tool("notion_API-post-page", notion_args)
        final_summary.append(f"Posted to Notion: {final_title}")

    else:
        execution_log.append("Branch B: Low volume arXiv results")
        # PubMed Search
        raw_pubmed = call_tool("pubmed_search_pubmed_key_words", {"key_words": "Chain of Thought"})
        pubmed_ids = []
        try:
            pd = json.loads(raw_pubmed) if isinstance(raw_pubmed, str) else raw_pubmed
            pubmed_ids = pd.get("result", []) if isinstance(pd, dict) else pd
        except:
            pass

        if pubmed_ids and len(pubmed_ids) > 0:
            execution_log.append("Sub-branch B1: PubMed results found")
            pmid = pubmed_ids[0] if isinstance(pubmed_ids[0], (str, int)) else pubmed_ids[0].get("uid")

            raw_meta = call_tool("pubmed_get_pubmed_article_metadata", {"pmid": pmid})
            meta_data = json.loads(raw_meta) if isinstance(raw_meta, str) else raw_meta
            # Extract title safely
            pm_title = "PubMed Article"
            if isinstance(meta_data, dict):
                res = meta_data.get("result", {})
                if isinstance(res, dict):
                    uid_data = res.get(str(pmid), {})
                    pm_title = uid_data.get("title", "PubMed Article")

            notion_args = {
                "parent": {"database_id": "db-123"},
                "properties": {
                    "Name": {
                        "title": [{"text": {"content": pm_title}}]
                    }
                }
            }
            call_tool("notion_API-post-page", notion_args)
            final_summary.append(f"Posted PubMed article to Notion: {pm_title}")
        else:
            execution_log.append("Sub-branch B2: No PubMed results")
            call_tool("filesystem_write_file", {
                "path": "/tmp/research_log.txt",
                "content": "No papers found this week"
            })
            final_summary.append("Wrote log file")

    # Step 3: Notification
    execution_log.append("Step 3: Checking Slack channels")
    raw_channels = call_tool("slack_channels_list", {"channel_types": "public_channel"})
    channels = []
    try:
        cd = json.loads(raw_channels) if isinstance(raw_channels, str) else raw_channels
        channels = cd.get("channels", []) if isinstance(cd, dict) else cd
    except:
        pass

    target_channel_id = None
    for ch in channels:
        if ch.get("name") == "research-sync":
            target_channel_id = ch.get("id")
            break

    if target_channel_id:
        execution_log.append("Branch C: Slack channel found")
        call_tool("slack_conversations_add_message", {
            "channel_id": target_channel_id,
            "payload": "Digest updated"
        })
        final_summary.append("Notified Slack")
    else:
        execution_log.append("Branch D: Slack channel missing")
        call_tool("google-workspace_send_email", {
            "to": "lead@example.com",
            "subject": "Digest updated",
            "body": "The weekly research digest has been processed."
        })
        final_summary.append("Sent Email")

    return "\n".join(execution_log + ["SUMMARY:"] + final_summary)

def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # Step 1: Get Weather
    location = "Yosemite Valley, CA"
    park_code = "yose"

    execution_log.append(f"Step 1: Checking weather for {location}")
    # Correct 2-arg call
    raw_weather = call_tool("weather-data_weather_current", {"q": location})
    execution_log.append(f"[RAW] {str(raw_weather)[:200]}")

    weather_data = {}
    if isinstance(raw_weather, str) and raw_weather.strip():
        try:
            weather_data = json.loads(raw_weather)
        except:
            pass
    elif isinstance(raw_weather, dict):
        weather_data = raw_weather

    # Defensive access to weather condition
    # WeatherAPI structure: {'current': {'condition': {'text': '...'}}}
    current = weather_data.get('current', {})
    condition = current.get('condition', {})
    condition_text = condition.get('text', 'Unknown').lower()

    execution_log.append(f"Current weather condition: {condition_text}")

    branch_result = None
    branch_name = ""

    # Step 2: Branching Logic
    if "rain" in condition_text:
        branch_name = "Rain -> Visitor Centers"
        execution_log.append(f"Branch Triggered: {branch_name}")
        raw_res = call_tool("national-parks_getVisitorCenters", {"parkCode": park_code})
    elif "snow" in condition_text:
        branch_name = "Snow -> Alerts"
        execution_log.append(f"Branch Triggered: {branch_name}")
        raw_res = call_tool("national-parks_getAlerts", {"parkCode": park_code})
    elif "clear" in condition_text or "sunny" in condition_text:
        branch_name = "Clear/Sunny -> Campgrounds"
        execution_log.append(f"Branch Triggered: {branch_name}")
        raw_res = call_tool("national-parks_getCampgrounds", {"parkCode": park_code})
    else:
        branch_name = "Default -> Events"
        execution_log.append(f"Branch Triggered: {branch_name}")
        raw_res = call_tool("national-parks_getEvents", {"parkCode": park_code})

    execution_log.append(f"[RAW] {str(raw_res)[:200]}")

    if isinstance(raw_res, str) and raw_res.strip():
        try:
            branch_result = json.loads(raw_res)
        except:
            branch_result = raw_res
    else:
        branch_result = raw_res

    # Step 3: Aggregation
    final_output = {
        "weather_condition": condition_text,
        "selected_branch": branch_name,
        "branch_data": branch_result
    }

    execution_log.append(f"Final Aggregated Result: {str(final_output)[:500]}")

    return "\n".join(execution_log)
